import vex

# Configure email-specific verification policies
vex_client = vex.VexClient(api_key="your-vex-key")

policies = {
    "pii_filter": {
        "type": "pii_detection",
        "threshold": "high",
        "block": True
    },
    "tone_check": {
        "type": "tone_analysis",
        "categories": ["professional", "polite", "non_offensive"],
        "min_score": 0.9
    },
    "recipient_check": {
        "type": "recipient_validation",
        "allowed_domains": ["company.com", "partner.org"],
        "max_recipients": 10
    },
    "confidentiality": {
        "type": "confidentiality_check",
        "keywords": ["confidential", "proprietary", "internal"],
        "action": "redact"
    }
}

for policy_name, config in policies.items():
    vex_client.create_policy(policy_name, config)

print("Vex policies configured for email assistant")

